from typing import List

class Solution:
    def maxWidthRamp(self, nums: List[int]) -> int:
        mono_stack = []
        ramp = 0

        # pass 1 — build strictly decreasing stack of candidate left endpoints
        for i in range(len(nums)):
            if not mono_stack or mono_stack[-1][1] > nums[i]:
                mono_stack.append((i, nums[i]))

        # pass 2 — sweep j from right to find farthest valid right for each left
        j = len(nums) - 1
        while j >= 0 and mono_stack:
            if mono_stack[-1][1] <= nums[j]:
                # valid ramp: left index from stack, right index is j
                left, _ = mono_stack.pop()
                ramp = max(ramp, j - left)
                # don't decrement j — same j might match next stack entry
            else:
                j -= 1  # current j can't satisfy stack top — try smaller j

        return ramp

        # Time Complexity:  O(n) — each element pushed/popped at most once, j moves at most n steps
        # Space Complexity: O(n) — the stack holds at most n entries

